     7  // V36 migrates dashboard datasource references from legacy string format to structured UID-based objects.
     8  //
     9  // This migration addresses a critical evolution in Grafana's datasource architecture where datasource
    10  // identification shifted from potentially ambiguous display names to reliable UIDs. The original format
    11  // used string references that could break when datasources were renamed, moved between organizations,
    12  // or when multiple datasources shared similar names. This created reliability and portability issues
    13  // for dashboard sharing and automation workflows.
    14  //
    15  // The migration works by:
    16  // 1. Processing annotations, template variables, and panels (including nested panels in rows)
    17  // 2. Converting string datasource references to structured objects containing uid, type, and apiVersion
    18  // 3. Handling null/missing datasource references by setting appropriate defaults
    19  // 4. Maintaining consistency between panel and target datasource configurations
    20  // 5. Preserving special datasource types like Mixed datasources and expression queries
    21  //
    22  // This transformation provides several critical benefits:
    23  // - Eliminates datasource reference breakage when datasources are renamed
    24  // - Enables reliable dashboard export/import across different Grafana instances
    25  // - Supports advanced datasource features that require type and version information
    26  // - Prepares the schema for future datasource management enhancements
    27  // - Maintains backward compatibility while establishing a robust foundation
    28  //
    29  // The migration handles complex scenarios including:
    30  // - Panels with missing datasource configuration (set to default)
    31  // - Mixed datasource panels with heterogeneous targets
    32  // - Expression queries that reference other queries
    33  // - Template variables that depend on datasource queries
    34  // - Annotation queries from various datasource types
    35  //
    36  // Example transformations:
    37  //
    38  // Before migration (string reference):
    39  //
    40  //      datasource: "prometheus-prod"
    41  //      // or
    42  //      datasource: null
    43  //
    44  // After migration (structured object):
    45  //
    46  //      datasource: {
    47  //        uid: "prometheus-uid-123",
    48  //        type: "prometheus",
    49  //        apiVersion: "v1"
    50  //      }
    51  //
    52  // Before migration (panel with targets):
    53  //
    54  //      panel: {
    55  //        datasource: "CloudWatch",
    56  //        targets: [{
    57  //          datasource: null,
    58  //          refId: "A"
    59  //        }]
    60  //      }
    61  //
    62  // After migration (consistent references):
    63  //
    64  //      panel: {
    65  //        datasource: {
    66  //          uid: "cloudwatch-uid-456",
    67  //          type: "cloudwatch",
    68  //          apiVersion: "v1"
    69  //        },
    70  //        targets: [{
    71  //          datasource: {
    72  //            uid: "cloudwatch-uid-456",
    73  //            type: "cloudwatch",
    74  //            apiVersion: "v1"
    75  //          },
    76  //          refId: "A"
    77  //        }]
    78  //      }
    79  func V36(dsInfo DataSourceInfoProvider) SchemaVersionMigrationFunc {
    80          return func(ctx context.Context, dashboard map[string]interface{}) error {
    81                  datasources := dsInfo.GetDataSourceInfo(ctx)
    82                  dashboard["schemaVersion"] = int(36)
    83
    84                  migrateAnnotations(dashboard, datasources)
    85                  migrateTemplateVariables(dashboard, datasources)
    86                  migratePanels(dashboard, datasources)
    87
    88                  return nil
    89          }
    90  }
    91
    92  // migrateAnnotations updates datasource references in dashboard annotations
    93  func migrateAnnotations(dashboard map[string]interface{}, datasources []DataSourceInfo) {
    94          annotations, ok := dashboard["annotations"].(map[string]interface{})
    95          if !ok {
    96                  return
    97          }
    98
    99          list, ok := annotations["list"].([]interface{})
   100          if !ok {
   101                  return
   102          }
   103
   104          for _, query := range list {
   105                  queryMap, ok := query.(map[string]interface{})
   106                  if !ok {
   107                          continue
   108                  }
   109
   110                  // Always migrate datasource, even if it doesn't exist (will be set to default)
   111                  ds := queryMap["datasource"]
   112                  queryMap["datasource"] = MigrateDatasourceNameToRef(ds, map[string]bool{"returnDefaultAsNull": false}, datasources)
   113          }
   114  }
   115
   116  // migrateTemplateVariables updates datasource references in dashboard variables
   117  func migrateTemplateVariables(dashboard map[string]interface{}, datasources []DataSourceInfo) {
   118          templating, ok := dashboard["templating"].(map[string]interface{})
   119          if !ok {
   120                  return
   121          }
   122
   123          list, ok := templating["list"].([]interface{})
   124          if !ok {
   125                  return
   126          }
   127
   128          defaultDS := GetDefaultDSInstanceSettings(datasources)
   129          for _, variable := range list {
   130                  varMap, ok := variable.(map[string]interface{})
   131                  if !ok {
   132                          continue
   133                  }
   134
   135                  varType := GetStringValue(varMap, "type")
   136                  if varType != "query" {
   137                          continue
   138                  }
   139
   140                  ds, exists := varMap["datasource"]
   141                  // Handle null datasource variables by setting to default (matches frontend behavior)
   142                  // Only add datasource if it's explicitly null, not if it doesn't exist
   143                  if exists && ds == nil {
   144                          varMap["datasource"] = GetDataSourceRef(defaultDS)
   145                  }
   146                  // Note: Frontend v36 migration only converts null datasources to default objects
   147                  // It does NOT convert string datasources to objects, so we should not do that either
   148          }
   149  }
   150
   151  // migratePanels updates datasource references in dashboard panels
   152  func migratePanels(dashboard map[string]interface{}, datasources []DataSourceInfo) {
   153          panels, ok := dashboard["panels"].([]interface{})
   154          if !ok {
   155                  return
   156          }
   157
   158          for _, panel := range panels {
   159                  panelMap, ok := panel.(map[string]interface{})
   160                  if !ok {
   161                          continue
   162                  }
   163                  migratePanelDatasources(panelMap, datasources)
   164
   165                  // Handle nested panels in collapsed rows
   166                  nestedPanels, hasNested := panelMap["panels"].([]interface{})
   167                  if !hasNested {
   168                          continue
   169                  }
   170
   171                  for _, nestedPanel := range nestedPanels {
   172                          np, ok := nestedPanel.(map[string]interface{})
   173                          if !ok {
   174                                  continue
   175                          }
   176                          migratePanelDatasourcesInternal(np, datasources, true)
   177                  }
   178          }
   179  }
   180
   181  // migratePanelDatasources updates datasource references in a single panel and its targets
   182  func migratePanelDatasources(panelMap map[string]interface{}, datasources []DataSourceInfo) {
   183          migratePanelDatasourcesInternal(panelMap, datasources, false)
   184  }
   185
   186  // migratePanelDatasourcesInternal updates datasource references with nesting awareness
   187  func migratePanelDatasourcesInternal(panelMap map[string]interface{}, datasources []DataSourceInfo, isNested bool) {
   188          // NOTE: Even though row panels don't technically need datasource or targets fields,
   189          // we process them anyway to exactly match frontend behavior and avoid inconsistencies
   190          // between frontend and backend migrations. The frontend DashboardMigrator processes
   191          // all panels uniformly without special row panel handling.
   192
   193          defaultDS := GetDefaultDSInstanceSettings(datasources)
   194          panelDataSourceWasDefault := false
   195
   196          // Handle targets - only add default targets to top-level panels (matches frontend behavior)
   197          targets, hasTargets := panelMap["targets"].([]interface{})
   198          if !hasTargets || len(targets) == 0 {
   199                  if !isNested {
   200                          // Add default target to top-level panels only
   201                          targets = []interface{}{
   202                                  map[string]interface{}{
   203                                          "refId": "A",
   204                                  },
   205                          }
   206                          panelMap["targets"] = targets
   207                          hasTargets = true
   208                  } else {
   209                          // Nested panels without targets are not processed
   210                          return
   211                  }
   212          }
   213
   214          // Handle panel datasource
   215          ds, exists := panelMap["datasource"]
   216          if !exists || ds == nil {
   217                  // Set to default if panel has targets with length > 0 (matches frontend logic)
   218                  if len(targets) > 0 {
   219                          // Matches frontend: panel.datasource = getDataSourceRef(defaultDs)
   220                          panelMap["datasource"] = GetDataSourceRef(defaultDS)
   221                          panelDataSourceWasDefault = true
   222                  }
   223          } else {
   224                  // Migrate existing non-null datasource
   225                  // Frontend preserves existing datasource objects as-is, so backend should too
   226                  // But don't override empty objects {} that were set by previous migrations (like V33)
   227                  if dsMap, ok := ds.(map[string]interface{}); ok && len(dsMap) == 0 {
   228                          // Keep empty object {} as-is (set by V33 migration for empty strings)
   229                          panelMap["datasource"] = ds
   230                  } else {
   231                          migrated := MigrateDatasourceNameToRef(ds, map[string]bool{"returnDefaultAsNull": false}, datasources)
   232                          panelMap["datasource"] = migrated
   233                  }
   234          }
   235
   236          // Handle target datasources
   237          if !hasTargets {
   238                  return
   239          }
   240
   241          for _, target := range targets {
   242                  targetMap, ok := target.(map[string]interface{})
   243                  if !ok {
   244                          continue
   245                  }
   246
   247                  ds, exists := targetMap["datasource"]
   248
   249                  // Check if target datasource is null, missing, or has no uid
   250                  needsDefault := false
   251                  if !exists || ds == nil {
   252                          needsDefault = true
   253                  } else if dsMap, ok := ds.(map[string]interface{}); ok {
   254                          uid, hasUID := dsMap["uid"]
   255                          if !hasUID || uid == nil {
   256                                  needsDefault = true
   257                          }
   258                  }
   259
   260                  if needsDefault {
   261                          // Frontend: if (panel.datasource?.uid !== MIXED_DATASOURCE_NAME) { target.datasource = { ...panel.datasource }; }
   262                          panelDS, ok := panelMap["datasource"].(map[string]interface{})
   263                          if ok {
   264                                  uid := GetStringValue(panelDS, "uid")
   265                                  isMixed := uid == "-- Mixed --"
   266
   267                                  if !isMixed {
   268                                          // Spread the panel datasource properties (mimics frontend: { ...panel.datasource })
   269                                          result := make(map[string]interface{})
   270                                          for k, v := range panelDS {
   271                                                  result[k] = v
   272                                          }
   273                                          targetMap["datasource"] = result
   274                                  } else {
   275                                          // Frontend: target.datasource = migrateDatasourceNameToRef(target.datasource, { returnDefaultAsNull: false });
   276                                          targetMap["datasource"] = MigrateDatasourceNameToRef(ds, map[string]bool{"returnDefaultAsNull": false}, datasources)
   277                                  }
   278                          }
   279                  } else {
   280                          // Migrate existing target datasource
   281                          targetMap["datasource"] = MigrateDatasourceNameToRef(ds, map[string]bool{"returnDefaultAsNull": false}, datasources)
   282                  }
   283
   284                  // Update panel datasource if it was default and target is not an expression
   285                  if panelDataSourceWasDefault {
   286                          targetDS, ok := targetMap["datasource"].(map[string]interface{})
   287                          if ok {
   288                                  uid := GetStringValue(targetDS, "uid")
   289                                  if uid != "" && uid != "__expr__" {
   290                                          panelMap["datasource"] = targetDS
   291                                  }
   292                          }
   293                  }
   294          }
   295  }

